it('should handle complete user lifecycle: create user → place order → update status', async () => {
  // Step 1: User created → welcome email
  await eventBus.emit({
    type: 'user:created',
    user: testUser,
    timestamp: new Date(),
  } satisfies UserCreatedEvent);

  // Step 2: Order created → confirmation email
  await eventBus.emit({
    type: 'order:created',
    order: testOrder,
    user: testUser,
    timestamp: new Date(),
  } satisfies OrderCreatedEvent);

  // Step 3: Order shipped → status update
  // NOTE: handleOrderStatusChanged uses event.order.userId as recipient,
  // which is not a valid email. The EmailAdapter will reject it, resulting
  // in a 'failed' notification. This is a known integration issue — the
  // OrderStatusChangedEvent doesn't carry user email.
  await eventBus.emit({
    type: 'order:status-changed',
    order: { ...testOrder, status: 'shipped' },
    previousStatus: 'pending',
    newStatus: 'shipped',
    timestamp: new Date(),
  } satisfies OrderStatusChangedEvent);

  // All 3 notifications stored
  const notifications = notificationService.getNotifications();
  expect(notifications).toHaveLength(3);

  // First two succeed (valid email), third fails (userId not a valid email)
  expect(notifications[0]!.status).toBe('sent');
  expect(notifications[0]!.type).toBe('user:welcome');
  expect(notifications[1]!.status).toBe('sent');
  expect(notifications[1]!.type).toBe('order:confirmation');
  expect(notifications[2]!.status).toBe('failed');
  expect(notifications[2]!.type).toBe('order:status-update');

  // 2 emails actually delivered (the third was rejected by the adapter)
  const emails = emailTransport.getSentEmails();
  expect(emails).toHaveLength(2);
  expect(emails[0]!.subject).toBe('Welcome to TaskFlow Pro!');
  expect(emails[1]!.subject).toContain('Order Confirmation');

  // All 3 logged in history
  const history = historyService.getAll();
  expect(history).toHaveLength(3);
  expect(history[0]!.status).toBe('sent');
  expect(history[1]!.status).toBe('sent');
  expect(history[2]!.status).toBe('failed');
});

