+      const slowTransport: EmailTransport = {
+        async sendMail(email) {
+          const delay = delays[callIndex++] ?? 0;
+          await new Promise((resolve) => setTimeout(resolve, delay));
+          deliveryOrder.push(email.subject);
+          return { success: true };
+        },
+      };
+
+      const slowEmailAdapter = new EmailAdapter(
+        { fromAddress: 'noreply@taskflowpro.com', appName: 'TaskFlow Pro' },
