+
+  // ──────────────────────────────────────────────────────────
+  // Full pipeline end-to-end
+  // ──────────────────────────────────────────────────────────
+
+  describe('full pipeline end-to-end', () => {
+    it('should handle complete user lifecycle: create user → place order → update status', async () => {
+      // Step 1: User created → welcome email
+      await eventBus.emit({
+        type: 'user:created',
