+      expect(notifications[0]!.type).toBe('user:welcome');
+      expect(notifications[1]!.status).toBe('sent');
+      expect(notifications[1]!.type).toBe('order:confirmation');
+      expect(notifications[2]!.status).toBe('failed');
+      expect(notifications[2]!.type).toBe('order:status-update');
+
+      // 2 emails actually delivered (the third was rejected by the adapter)
+      const emails = emailTransport.getSentEmails();
+      expect(emails).toHaveLength(2);
+      expect(emails[0]!.subject).toBe('Welcome to TaskFlow Pro!');
+      expect(emails[1]!.subject).toContain('Order Confirmation');
+
+      // All 3 logged in history
+      const history = historyService.getAll();
+      expect(history).toHaveLength(3);
+      expect(history[0]!.status).toBe('sent');
+      expect(history[1]!.status).toBe('sent');
+      expect(history[2]!.status).toBe('failed');
+    });
+
+    it('should handle mixed sent and suppressed in same pipeline run', async () => {
+      // Allow welcome emails but block order notifications
+      preferencesService.updateEmailPreferences('user-1', {
+        subscribedCategories: ['user:welcome'],
+      });
+
+      await eventBus.emit({
+        type: 'user:created',
+        user: testUser,
+        timestamp: new Date(),
+      } satisfies UserCreatedEvent);
+
+      await eventBus.emit({
+        type: 'order:created',
+        order: testOrder,
+        user: testUser,
+        timestamp: new Date(),
+      } satisfies OrderCreatedEvent);
+
+      // Only the welcome email should be sent
+      const emails = emailTransport.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]!.subject).toBe('Welcome to TaskFlow Pro!');
+
+      // Notifications: only the welcome one stored (suppressed returns null)
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]!.type).toBe('user:welcome');
